#!/usr/bin/env node
const config=require("./config"),DiscordNotifier=require("./services/discordNotifier");async function startDiscordBot(){let notifier;console.log("🤖 Starting Discord Bot with Slash Commands..."),console.log("=".repeat(50));try{notifier=new DiscordNotifier,console.log("✅ DiscordNotifier instance created"),console.log("🔗 Connecting to Discord..."),await notifier.connect(),console.log("✅ Connected to Discord successfully"),console.log("\n🎉 Discord Bot is now running!"),console.log("💡 You can now use /collection command in Discord"),console.log("🛑 Press Ctrl+C to stop the bot"),console.log("=".repeat(50)),process.stdin.resume()}catch(error){console.error("❌ Error starting Discord bot:",error),process.exit(1)}}process.on("SIGINT",(async()=>{console.log("\n🛑 Shutting down Discord Bot..."),notifier&&await notifier.disconnect(),process.exit(0)})),process.on("SIGTERM",(async()=>{console.log("\n🛑 Shutting down Discord Bot..."),notifier&&await notifier.disconnect(),process.exit(0)})),startDiscordBot();